import React, { useState } from "react";
import "./CalendarOverlay.css";

const CalendarOverlay = ({ isOpen, onClose }) => {
  const [currentDate, setCurrentDate] = useState(new Date()); // Поточна дата перегляду

  if (!isOpen) return null;

  const daysOfWeek = ["MON", "TUE", "WED", "THU", "FRI", "SAT", "SUN"];

  // Отримуємо дані для відображення
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();

  // Назва місяця для заголовка
  const monthName = currentDate.toLocaleString("en-US", { month: "long" });

  // Логіка генерації днів
  const firstDayOfMonth = new Date(year, month, 1).getDay();
  // Коригуємо, щоб тиждень починався з понеділка (0 - Пн, 6 - Нд)
  const offset = firstDayOfMonth === 0 ? 6 : firstDayOfMonth - 1;
  const daysInMonth = new Date(year, month + 1, 0).getDate();

  const dates = [];
  for (let i = 0; i < offset; i++) dates.push(""); // Пусті клітинки на початку
  for (let d = 1; d <= daysInMonth; d++) dates.push(d);

  // Функції перемикання
  const changeMonth = (offset) => {
    setCurrentDate(new Date(year, month + offset, 1));
  };

  const changeYear = (offset) => {
    setCurrentDate(new Date(year + offset, month, 1));
  };

  const isToday = (day) => {
    const today = new Date();
    return (
      today.getDate() === day &&
      today.getMonth() === month &&
      today.getFullYear() === year
    );
  };

  return (
    <div className="calendar-modal-overlay">
      <div className="calendar-container">
        <div className="calendar-header">
          <h2 className="calendar-title">Calendar</h2>
          <button className="back-arrow-btn" onClick={onClose}>
            ↩
          </button>
        </div>

        {/* Вибір Року (швидке перемикання) */}
        <div className="year-navigation">
          <button onClick={() => changeYear(-1)} className="nav-arrow">
            «
          </button>
          <span className="current-year">{year}</span>
          <button onClick={() => changeYear(1)} className="nav-arrow">
            »
          </button>
        </div>

        {/* Вибір Місяця */}
        <div className="month-navigation">
          <button className="nav-btn" onClick={() => changeMonth(-1)}>
            {"<"}
          </button>
          <span className="current-month">{monthName}</span>
          <button className="nav-btn" onClick={() => changeMonth(1)}>
            {">"}
          </button>
        </div>

        <div className="days-header">
          {daysOfWeek.map((day) => (
            <span key={day} className="day-name">
              {day}
            </span>
          ))}
        </div>

        <div className="calendar-grid">
          {dates.map((date, index) => (
            <div
              key={index}
              className={`calendar-date ${isToday(date) ? "active-date" : ""} ${date === "" ? "empty" : ""}`}
            >
              {date}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default CalendarOverlay;
